package main

import (
	"errors"
	"sync"
)

type BankAccount struct {
	mu       sync.RWMutex
	accounts map[string]int64
}

func NewBankAccount() *BankAccount {
	return &BankAccount{
		accounts: make(map[string]int64),
	}
}

func (b *BankAccount) CreateAccount(accountID string, initialBalance int64) error {
	b.mu.Lock()
	defer b.mu.Unlock()

	if _, exists := b.accounts[accountID]; exists {
		return errors.New("account already exists")
	}

	b.accounts[accountID] = initialBalance
	return nil
}

func (b *BankAccount) GetBalance(accountID string) (int64, error) {
	b.mu.RLock()
	defer b.mu.RUnlock()

	balance, exists := b.accounts[accountID]
	if !exists {
		return 0, errors.New("account not found")
	}

	return balance, nil
}

func (b *BankAccount) Deposit(accountID string, amount int64) error {
	if amount <= 0 {
		return errors.New("deposit amount must be positive")
	}

	b.mu.Lock()
	defer b.mu.Unlock()

	balance, exists := b.accounts[accountID]
	if !exists {
		return errors.New("account not found")
	}

	b.accounts[accountID] = balance + amount
	return nil
}

func (b *BankAccount) Withdraw(accountID string, amount int64) error {
	if amount <= 0 {
		return errors.New("withdrawal amount must be positive")
	}

	b.mu.Lock()
	defer b.mu.Unlock()

	balance, exists := b.accounts[accountID]
	if !exists {
		return errors.New("account not found")
	}

	if balance < amount {
		return errors.New("insufficient funds")
	}

	b.accounts[accountID] = balance - amount
	return nil
}

func (b *BankAccount) Transfer(fromAccountID, toAccountID string, amount int64) error {
	if amount <= 0 {
		return errors.New("transfer amount must be positive")
	}

	b.mu.Lock()
	defer b.mu.Unlock()

	fromBalance, fromExists := b.accounts[fromAccountID]
	if !fromExists {
		return errors.New("source account not found")
	}

	_, toExists := b.accounts[toAccountID]
	if !toExists {
		return errors.New("destination account not found")
	}

	if fromBalance < amount {
		return errors.New("insufficient funds")
	}

	b.accounts[fromAccountID] = fromBalance - amount
	b.accounts[toAccountID] = b.accounts[toAccountID] + amount

	return nil
}

func (b *BankAccount) ProcessTransactions(transactions []func() error) []error {
	results := make([]error, len(transactions))
	var wg sync.WaitGroup

	for i, txn := range transactions {
		wg.Add(1)
		go func(index int, transaction func() error) {
			defer wg.Done()
			results[index] = transaction()
		}(i, txn)
	}

	wg.Wait()
	return results
}